        s_fixture = new Fixture();
        await s_fixture!.InitializeAsync();
    }

    [ClassCleanup]
    public static async Task ClassCleanup()
    {
        if (s_fixture is not null)
        {
            await s_fixture!.DisposeAsync();
        }
    }

    [TestMethod]
    public void TestNumberIsValid()
    {
        using var doc = JsonDocument.Parse("1");
        IJsonValue instance = JsonSchemaBuilderDriver.CreateInstance(s_fixture!.GeneratedType, doc.RootElement);
        Assert.IsTrue(instance.Validate(ValidationContext.ValidContext).IsValid);
    }

    [TestMethod]
    public void TestNonNumberIsInvalid()
    {
        using var doc = JsonDocument.Parse("\"a\"");
        IJsonValue instance = JsonSchemaBuilderDriver.CreateInstance(s_fixture!.GeneratedType, doc.RootElement);
        Assert.IsFalse(instance.Validate(ValidationContext.ValidContext).IsValid);
    }

    public class Fixture
    {
        private JsonSchemaBuilderDriver? _driver;

        public global::System.Type GeneratedType { get; private set; } = null!;

        public async Task InitializeAsync()
        {
            _driver = DriverFactory.CreateDraft202012Driver();
            GeneratedType = await _driver.GenerateTypeForJsonSchemaTestSuite(
                "refRemote.json",
                "#/14/schema",
                "JsonSchemaTestSuiteDraft202012RefRemote",
                "RefToRefFindsDetachedAnchor",
                validateFormat: false,
                optionalAsNullable: false,
                useImplicitOperatorString: false);
        }

        public Task DisposeAsync()
        {
            _driver?.Dispose();
            return Task.CompletedTask;
        }
    }
}
